  const elAddress = $("#dapp-contract-address");
  const elMethod = $("#dapp-method");
  const elAbi = $("#dapp-abi");
  const elArgs = $("#dapp-args");
  const elArgTypes = $("#dapp-argtypes");
  const elCallType = $("#dapp-calltype");
  const elTxValue = $("#dapp-tx-value");
  const elValueType = $("#dapp-value-type");
  const elValueDecimals = $("#dapp-value-decimals");
  const elGasLimit = $("#dapp-gaslimit");
  const elMaxFee = $("#dapp-maxfeepergas");
  const elMaxPrio = $("#dapp-maxpriorityfee");
  const elSend = $("#dapp-send");
  const elBuildTx = $("#dapp-buildtx");
  const elEstimateGas = $("#dapp-estimategas");
  const elClear = $("#dapp-clear");
  const elOutput = $("#dapp-output");

  const setOut = (obj) => {
    if (typeof obj === "string") elOutput.textContent += obj + "\n";
    else elOutput.textContent += JSON.stringify(obj, (k, v) => (typeof v === "bigint" ? v.toString() : v), 2) + "\n";
    elOutput.scrollTop = elOutput.scrollHeight;
  };

  const getJson = (text, fallback) => {
    const t = (text ?? "").trim();
    if (!t) return fallback;
    return JSON.parse(t);
  };

  const getInputs = () => {
    const address = (elAddress.value || "").trim();
    const method = (elMethod.value || "").trim();
    const abi = getJson(elAbi.value, null);
    const args = getJson(elArgs.value, []);
    const argTypes = getJson(elArgTypes.value, []);
    const txValue = (elTxValue.value || "").trim();
    const valueType = elValueType.value;
    const valueDecimals = Number((elValueDecimals.value || "18").trim() || "18");

    const gasLimit = (elGasLimit.value || "").trim();
    const maxFeePerGas = (elMaxFee.value || "").trim();
    const maxPriorityFeePerGas = (elMaxPrio.value || "").trim();

    const txParams = {
      value: txValue === "" ? undefined : txValue,
      valueType,
      valueDecimals,
      gasLimit: gasLimit === "" ? undefined : gasLimit,
      maxFeePerGas: maxFeePerGas === "" ? undefined : maxFeePerGas,
      maxPriorityFeePerGas: maxPriorityFeePerGas === "" ? undefined : maxPriorityFeePerGas,
    };

    return { address, method, abi, args, argTypes, txParams };
  };

